function load$GridAllocated$(z) {
  var f = z.get_element().parentForm, y = f.grid, w = y.get_element().parentForm, g = w.getItem('d73')._controlBehavior;
  if (w.getItemValue('ma_nt').toUpperCase() == w._baseCurrency.toUpperCase()) hidden$GridAllocated$Fields(z, 'cp_vc_nt, cp_bh_nt, cp_khac_nt');
  render$GridAllocated(f, g, z);
  z.add_itemValueChanged(onChange$GridAllocatedDetail$);
  z.$a = {
    cp_vc: '[cp_vc]:=[cp_vc_nt]*[$ty_gia]',
    cp_bh: '[cp_bh]:=[cp_bh_nt]*[$ty_gia]',
    cp_khac: '[cp_khac]:=[cp_khac_nt]*[$ty_gia]',
    cp_nt: '[cp_nt]:=[cp_vc_nt]+[cp_bh_nt]+[cp_khac_nt]',
    cp: '[cp]:=[cp_vc]+[cp_bh]+[cp_khac]'
  };
  z._focusWhenTabChanged();
}
function dispose$GridAllocated$(z) {
  z.$a = null;
  try {z.remove_itemValueChanged(onChange$GridAllocatedDetail$);} catch (ex) {}
}
function onChange$GridAllocatedDetail$(sender, eventArgs) {
  var o = eventArgs.get_object(), z = o.grid, f = z.get_element().parentForm, name = o.field.Name;
  var y = f.grid, w = y.get_element().parentForm, v = (f.getItemValue('ma_nt').toUpperCase() == w._baseCurrency.toUpperCase());
  switch (name) {
    case 'cp_vc_nt':
      z.validExpression(o, [z.$a.cp_vc, z.$a.cp_nt, z.$a.cp], null, null);
      break;
    case 'cp_bh_nt':
      z.validExpression(o, [z.$a.cp_bh, z.$a.cp_nt, z.$a.cp], null, null);
      break;
    case 'cp_khac_nt':
      z.validExpression(o, [z.$a.cp_khac, z.$a.cp_nt, z.$a.cp], null, null);
      break;
    case 'cp_bh':
    case 'cp_vc':
    case 'cp_khac':
      z.validExpression(o, [z.$a.cp], null, null);
      break;
    default:
      break;
  }
}
function render$GridAllocated(f, g, z) {
  for (var r = 0; r < g._rowCount; r++){
    z._appendRow(null, true);
    for (var i = 0; i < z._fields.length; i++) {
      z._setItemValue(r + 1, i + 1, g._getItemValue(r + 1, g._getColumnOrder(z._fields[i].Name)));
    }
  }
}
function hidden$GridAllocated$Fields(z, c) {
  var a = c.split(',');
  for (var i = 0; i < a.length; i++) {
    z._setColumnVisible(z._getColumnOrder($func.trim(a[i])), false);
  }
}
